"""Emission compliance tests for reviewers (auto-generated by pact)."""

from reviewers.reviewers import Reviewers


class TestEmissionCompliance:
    """Verify reviewers emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_filter_hunks_by_policy_emits_events(self):
        """Method filter_hunks_by_policy emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Reviewers(event_handler=handler)
        try:
            obj.filter_hunks_by_policy()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for filter_hunks_by_policy'
        assert len(completed) >= 1, 'No completed/error event for filter_hunks_by_policy'
        assert invoked[0].get("pact_key") == "PACT:reviewers:filter_hunks_by_policy"
        assert isinstance(invoked[0].get("input_classification"), list)

