    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Reviewers(event_handler=handler)
        try:
            obj.filter_hunks_by_policy()
        except (TypeError, Exception):
            pass
        try:
            obj.derive_decision()
        except (TypeError, Exception):
            pass
        try:
            obj.build_assessment()
        except (TypeError, Exception):
            pass
        try:
            obj.SecurityReviewer.review()
        except (TypeError, Exception):
            pass
        try:
            obj.CorrectnessReviewer.review()
        except (TypeError, Exception):
            pass
        try:
            obj.StyleReviewer.review()
        except (TypeError, Exception):
            pass
        try:
            obj.ArchitectureReviewer.review()
        except (TypeError, Exception):
            pass
        try:
            obj.get_all_reviewers()
        except (TypeError, Exception):
            pass
        try:
            obj.get_reviewer_by_stage()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:reviewers:"), f"Bad pact_key: {key}"

